const item = $input.first().json;
const TAVILY_KEY = $env.TAVILY_API_KEY;
const query = item.tavily_query || item.user.slice(0, 300);
var searchResp;
try {
  searchResp = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.tavily.com/search',
    body: { api_key: TAVILY_KEY, query: query, search_depth: 'advanced', max_results: 10, include_raw_content: true, include_answer: true },
    json: true
  });
} catch(e) {
  return [{ json: Object.assign({}, item, { tavily_ok: false, tavily_raw: '', raw_content_map: {} }) }];
}
var results = (searchResp.results || []).map(function(r) {
  return { title: r.title||'', url: r.url||'', content: (r.content||'').slice(0,600), score: r.score||0, published_date: r.published_date||null, raw_content: r.raw_content||'' };
});

// Build raw_content_map keyed by URL (keep ≤5000 chars per entry)
var raw_content_map = {};
results.forEach(function(r) {
  if (r.raw_content) raw_content_map[r.url] = r.raw_content.slice(0, 5000);
});

var enrichedLines = results.map(function(r, i) {
  return '[' + (i+1) + '] ' + r.title + '\n網址：' + r.url + '\n評分：' + r.score.toFixed(3) +
    (r.published_date ? '  日期：' + r.published_date : '') + '\n摘要：' + r.content;
});
return [{ json: Object.assign({}, item, {
  tavily_ok: true,
  tavily_raw: enrichedLines.join('\n\n---\n\n').slice(0, 14000),
  raw_content_map: raw_content_map
}) }];

