const resp = $input.first().json;
const prompt = $('Build search prompt').first().json;
const usage = resp.usage || {};
const blocks = resp.content || [];
const texts = blocks.filter(b => b.type === 'text').map(b => b.text);
const lastText = texts.length ? texts[texts.length - 1] : '';
let parsed;
try {
  const m = lastText.match(/\{[\s\S]*\}/);
  parsed = m ? JSON.parse(m[0]) : { execution_summary: lastText.slice(0,400), results: [] };
} catch (e) { parsed = { execution_summary: 'JSON parse failed', results: [] }; }
function normUrl(u) {
  u = (u || '').toString().trim();
  const qi = u.indexOf('?');
  if (qi >= 0) {
    const base = u.slice(0, qi);
    const drop = ['srsltid','utm_source','utm_medium','utm_campaign','utm_term','utm_content','fbclid','gclid','ref','spm'];
    const qs = u.slice(qi+1).split('&').filter(function(kv){ return drop.indexOf(kv.split('=')[0].toLowerCase()) < 0; });
    u = qs.length ? base + '?' + qs.join('&') : base;
  }
  if (u.length > 1 && u.charAt(u.length-1) === '/') u = u.slice(0,-1);
  return u;
}
let results = Array.isArray(parsed.results) ? parsed.results.slice(0, 20) : [];
const seen = new Set();
results = results.filter(r => { const u = normUrl(r.url || ''); if (!u || seen.has(u)) return false; seen.add(u); r.url = u; return true; });
const NOTION_TOKEN = $env.NOTION_INTEGRATION_TOKEN;
const DB06 = '3469ff25fdab83c98ff98107ee6a6a1c';
const NH = { 'Authorization': 'Bearer ' + NOTION_TOKEN, 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json' };
let existingUrls = new Set();
try {
  const q = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.notion.com/v1/databases/' + DB06 + '/query',
    headers: NH, body: { filter: { property: '對應內容', relation: { contains: prompt.db05_id } }, page_size: 100 }, json: true
  });
  (q.results || []).forEach(function(p) {
    const u = p.properties['對應連結'] && p.properties['對應連結'].url ? normUrl(p.properties['對應連結'].url) : '';
    if (u) existingUrls.add(u);
  });
} catch(e) {}
let deduped = 0;
results = results.filter(r => { if (existingUrls.has(r.url)) { deduped++; return false; } return true; });
const FILE_EXTS = ['.pdf','.doc','.docx','.xls','.xlsx','.ppt','.pptx'];
const cleanResults = results.map(r => ({
  title: (r.title || '').toString().slice(0, 180),
  url: (r.url || '').toString().slice(0, 1800),
  summary: (r.summary || '').toString().slice(0, 1500),
  file_url: (function() {
    const fu = (r.file_url || '').toString().trim().slice(0, 1800);
    if (!fu) return '';
    const fuLower = fu.toLowerCase().split('?')[0];
    return FILE_EXTS.some(function(ext){ return fuLower.endsWith(ext); }) ? fu : '';
  })()
}));
const input_tokens = parseInt(usage.input_tokens || 0);
const output_tokens = parseInt(usage.output_tokens || 0);
const cost_ntd = ((input_tokens*3 + output_tokens*15)/1000000*32).toFixed(2);
const usage_line = '進=' + input_tokens + ' 出=' + output_tokens + ' 成本NT' + cost_ntd + ' (Tavily+web search)';
const count = cleanResults.length;
const sanitize = s => (s || '').toString().replace(/[\s]+/g, ' ').trim().slice(0, 500);
const search_summary = (parsed.execution_summary || '') + ' | 採集 ' + count + ' 筆、跨次去重 ' + deduped + ' 筆 | ' + usage_line;
return [{ json: { db06_id: prompt.db06_id, db05_id: prompt.db05_id, ai_mode: prompt.ai_mode, sort_num: prompt.sort_num, mingxi_name: prompt.mingxi_name, count, deduped, results: cleanResults, search_summary, safe_summary: sanitize(parsed.execution_summary || ''), usage_line, has_results: count > 0 } }];

const item = $input.first().json;
const results = item.results || [];
const NOTION_TOKEN = $env.NOTION_INTEGRATION_TOKEN;
const DB06 = '3469ff25fdab83c98ff98107ee6a6a1c';
const NH = { 'Authorization': 'Bearer ' + NOTION_TOKEN, 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json' };
const rawContentMap = item.raw_content_map || {};
const sleep = ms => new Promise(r => setTimeout(r, ms));

function makeBlocks(text) {
  // Split into ≤1800 char chunks; return Notion paragraph block array (≤100 blocks)
  var CHUNK = 1800;
  var blocks = [];
  var i = 0;
  while (i < text.length && blocks.length < 100) {
    var chunk = text.slice(i, i + CHUNK);
    blocks.push({
      object: 'block',
      type: 'paragraph',
      paragraph: { rich_text: [{ type: 'text', text: { content: chunk } }] }
    });
    i += CHUNK;
  }
  return blocks;
}

let created = 0, failed = 0;
const createdPages = [];
for (var i = 0; i < results.length; i++) {
  var r = results[i];
  var props = {
    '明細名稱': { title: [{ text: { content: r.title || ('參考資料 ' + (i+1)) } }] },
    '明細類型': { select: { name: '資料參考' } },
    '明細內容': { rich_text: [{ text: { content: r.summary } }] },
    '對應連結': { url: r.url },
    '對應內容': { relation: [{ id: item.db05_id }] }
  };
  try {
    var resp = await this.helpers.httpRequest({ method: 'POST', url: 'https://api.notion.com/v1/pages', headers: NH, body: { parent: { database_id: DB06 }, properties: props }, json: true });
    var pageId = (resp.id || '').replace(/-/g, '');
    if (pageId) {
      // Write raw_content as paragraph blocks to page body
      var rawText = rawContentMap[r.url] || '';
      var blocks = rawText ? makeBlocks(rawText) : [{ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: '（未取得全文）' } }] } }];
      // POST blocks in batches of 100
      for (var b = 0; b < blocks.length; b += 100) {
        var batch = blocks.slice(b, b + 100);
        try {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: 'https://api.notion.com/v1/blocks/' + pageId.slice(0,8)+'-'+pageId.slice(8,12)+'-'+pageId.slice(12,16)+'-'+pageId.slice(16,20)+'-'+pageId.slice(20) + '/children',
            headers: NH,
            body: { children: batch },
            json: true
          });
        } catch(be) {}
        await sleep(150);
      }
    }
    createdPages.push({ notion_page_id: pageId, file_url: r.file_url || '' });
    created++;
  } catch(ex) {
    createdPages.push({ notion_page_id: null, file_url: r.file_url || '' });
    failed++;
  }
}
return [{ json: Object.assign({}, item, { pages_created: created, pages_failed: failed, created_pages: createdPages }) }];

const item = $input.first().json;
const createdPages = item.created_pages || [];
const NOTION_TOKEN = $env.NOTION_INTEGRATION_TOKEN;
const NH = { 'Authorization': 'Bearer ' + NOTION_TOKEN, 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json' };
const R2_ACCOUNT_ID = 'fcb1588857a0ce416df2003e79bb9915';
const R2_ACCESS_KEY = $env.R2_ACCESS_KEY;
const R2_SECRET = $env.R2_SECRET_KEY;
const R2_BUCKET = 'makesense-photos';
const R2_PUBLIC_URL = 'https://pub-23c93c89519e48958e84298739337568.r2.dev';
const crypto = require('crypto');
const FILE_EXTS = ['.pdf','.doc','.docx','.xls','.xlsx','.ppt','.pptx'];
const CONTENT_TYPES = { pdf:'application/pdf', doc:'application/msword', docx:'application/vnd.openxmlformats-officedocument.wordprocessingml.document', xls:'application/vnd.ms-excel', xlsx:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', ppt:'application/vnd.ms-powerpoint', pptx:'application/vnd.openxmlformats-officedocument.presentationml.presentation' };
const dash = id => id.replace(/^(.{8})(.{4})(.{4})(.{4})(.{12})$/, '$1-$2-$3-$4-$5');
const p2 = n => String(n).padStart(2, '0');
let downloaded = 0, files_failed = 0;
for (var i = 0; i < createdPages.length; i++) {
  var pg = createdPages[i];
  if (!pg.file_url || !pg.notion_page_id) continue;
  var fuLower = pg.file_url.toLowerCase().split('?')[0];
  if (!FILE_EXTS.some(function(ext){ return fuLower.endsWith(ext); })) continue;
  try {
    var dlResp = await this.helpers.httpRequest({
      method: 'GET', url: pg.file_url,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; makesense-bot/1.0)' },
      responseType: 'arraybuffer', returnFullResponse: true, ignoreHttpStatusErrors: true
    });
    if (!dlResp || dlResp.statusCode >= 400) { files_failed++; continue; }
    var raw = dlResp.body;
    var buf;
    if (Buffer.isBuffer(raw)) buf = raw;
    else if (raw instanceof ArrayBuffer || ArrayBuffer.isView(raw)) buf = Buffer.from(raw);
    else if (typeof raw === 'string') buf = Buffer.from(raw, 'binary');
    else { files_failed++; continue; }
    if (buf.length === 0) { files_failed++; continue; }
    var extMatch = fuLower.match(/\.(pdf|docx|doc|xlsx|xls|pptx|ppt)$/);
    var ext = extMatch ? extMatch[1] : 'pdf';
    var contentType = CONTENT_TYPES[ext] || 'application/octet-stream';
    var key = 'db06_documents/' + pg.notion_page_id.substring(0,8) + '_' + i + '.' + ext;
    var host = R2_ACCOUNT_ID + '.r2.cloudflarestorage.com';
    var bucketPath = '/' + R2_BUCKET + '/' + key;
    var endpoint = 'https://' + host + bucketPath;
    var now = new Date();
    var dateStr = now.getUTCFullYear() + p2(now.getUTCMonth()+1) + p2(now.getUTCDate()) +
      'T' + p2(now.getUTCHours()) + p2(now.getUTCMinutes()) + p2(now.getUTCSeconds()) + 'Z';
    var dateShort = dateStr.slice(0,8);
    var payloadHash = 'UNSIGNED-PAYLOAD';
    var canonicalHeaders = 'content-type:' + contentType + '\nhost:' + host + '\nx-amz-content-sha256:' + payloadHash + '\nx-amz-date:' + dateStr + '\n';
    var signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';
    var canonicalRequest = 'PUT\n' + bucketPath + '\n\n' + canonicalHeaders + '\n' + signedHeaders + '\n' + payloadHash;
    var credScope = dateShort + '/auto/s3/aws4_request';
    var stringToSign = 'AWS4-HMAC-SHA256\n' + dateStr + '\n' + credScope + '\n' + crypto.createHash('sha256').update(canonicalRequest).digest('hex');
    var hmac = function(k, d){ return crypto.createHmac('sha256', k).update(d).digest(); };
    var sigKey = hmac(hmac(hmac(hmac(Buffer.from('AWS4' + R2_SECRET), dateShort), 'auto'), 's3'), 'aws4_request');
    var signature = crypto.createHmac('sha256', sigKey).update(stringToSign).digest('hex');
    var authorization = 'AWS4-HMAC-SHA256 Credential=' + R2_ACCESS_KEY + '/' + credScope + ',SignedHeaders=' + signedHeaders + ',Signature=' + signature;
    var putResp = await this.helpers.httpRequest({
      method: 'PUT', url: endpoint,
      headers: { 'Content-Type': contentType, 'Content-Length': String(buf.length), 'x-amz-content-sha256': payloadHash, 'x-amz-date': dateStr, 'Authorization': authorization },
      body: buf, returnFullResponse: true, ignoreHttpStatusErrors: true
    });
    if (!putResp || putResp.statusCode < 200 || putResp.statusCode >= 300) { files_failed++; continue; }
    var r2Url = R2_PUBLIC_URL.replace(/\/$/, '') + '/' + key;
    var fileName = pg.file_url.split('/').pop().split('?')[0] || ('file.' + ext);
    var dashedId = dash(pg.notion_page_id);
    await this.helpers.httpRequest({
      method: 'PATCH', url: 'https://api.notion.com/v1/pages/' + dashedId, headers: NH,
      body: { properties: { '上傳檔案': { files: [{ type: 'external', name: fileName, external: { url: r2Url } }] } } },
      json: true
    });
    downloaded++;
  } catch(e) { files_failed++; }
}
return [{ json: Object.assign({}, item, { files_downloaded: downloaded, files_failed: files_failed }) }];

const item = $input.first().json;
const createdPages = item.created_pages || [];
const NOTION_TOKEN = $env.NOTION_INTEGRATION_TOKEN;
const NH = { 'Authorization': 'Bearer ' + NOTION_TOKEN, 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json' };
const db06_id = item.db06_id;
const dash = id => id.replace(/^(.{8})(.{4})(.{4})(.{4})(.{12})$/, '$1-$2-$3-$4-$5');
const newIds = createdPages.filter(p => p.notion_page_id).map(p => p.notion_page_id);
if (newIds.length === 0) return [{ json: item }];
let existingIds = [];
try {
  const pg = await this.helpers.httpRequest({ method: 'GET', url: 'https://api.notion.com/v1/pages/' + dash(db06_id), headers: NH, json: true });
  existingIds = ((pg.properties['對應明細'] && pg.properties['對應明細'].relation) || []).map(r => r.id.replace(/-/g, ''));
} catch(e) {}
const allIds = Array.from(new Set([...existingIds, ...newIds]));
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: 'https://api.notion.com/v1/pages/' + dash(db06_id),
    headers: NH,
    body: { properties: { '對應明細': { relation: allIds.map(id => ({ id: dash(id) })) } } },
    json: true
  });
} catch(e2) {}
return [{ json: item }];

const row = $input.first().json || {};
const pc = $('Parse Claude').first().json;
const dl = $('下載並上傳檔案').first().json;
const auto_mode = row.auto_mode === true;
const reply_to = parseInt(row.last_msg_id || 0) || 0;
const filesLine = (dl.files_downloaded > 0 ? '
下載檔案 ' + dl.files_downloaded + ' 個' + (dl.files_failed > 0 ? '（失敗 ' + dl.files_failed + '）' : '') : '');
const base = '關卡B 成果確認
第 ' + (pc.sort_num != null ? pc.sort_num : '?') + ' 棒 (' + pc.ai_mode + ') 已完成。
DB06 頁面 ' + pc.db06_id + '

執行備註:
' + pc.safe_summary + '

採集 ' + pc.count + ' 筆、跨次去重 ' + (pc.deduped || 0) + ' 筆（Tavily+web search）。' + filesLine + '
tokens ' + pc.usage_line;
const manual_msg = base + '

按 OK 進下一棒，按 OK ALL 之後全自動。要 redo 重跑請打字 reply。
gateB db06=' + pc.db06_id;
const auto_msg = base + '

[全自動模式] 自動進下一棒，免按。';
return [{ json: { auto_mode, reply_to, flow_id: pc.db05_id, db05_id: pc.db05_id, db06_id: pc.db06_id, sort_num: pc.sort_num, ai_mode: pc.ai_mode, manual_msg, auto_msg, cb_ok: 'B1:' + pc.db06_id, cb_all: 'BA:' + pc.db06_id } }];

const results = $input.first().json.results || [];
const g = $('Build gateB').first().json;
const pending = results.filter(p => (p.properties['ai狀態']?.status?.name||'') !== '完成');
const total = results.length;
if (pending.length === 0) {
  return [{ json: { has_next: false, tg_message: '全套完成 共 ' + total + ' 棒已全部通過 (全自動模式)。' } }];
}
